import React, { useState, useEffect } from "react";
import ReactMapGL, { Marker, Popup } from "react-map-gl";
import 'mapbox-gl/dist/mapbox-gl.css';

function BreakingNewsMarquee({ hotspots }) {
  const [isPaused, setIsPaused] = useState(false);

  if (!hotspots || hotspots.length === 0) {
    return (
      <div style={{
        height: "40px",
        minHeight: "40px",
        flexShrink: 0,
        flexGrow: 0,
        width: "100%",
        backgroundColor: "#1a1a1a",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        borderBottom: "1px solid #333"
      }}>
        <span style={{ color: "#aaa", fontSize: "14px" }}>No news available</span>
      </div>
    );
  }

  // Render the headline list — called twice so the scroll loop is seamless
  const renderHeadlines = (keyPrefix) =>
    hotspots.map((spot, i) => (
      <span
        key={`${keyPrefix}-${i}`}
        onClick={() => window.open(spot.url, "_blank")}
        style={{
          display: "inline-flex",
          alignItems: "center",
          color: "#0077cc",
          cursor: "pointer",
          fontSize: "14px",
          marginRight: "48px",
          whiteSpace: "nowrap"
        }}
      >
        🔴&nbsp;{spot.title}
      </span>
    ));

  const animationDuration = Math.max(20, hotspots.length * 6);

  return (
    <div
      style={{
        height: "40px",
        minHeight: "40px",
        flexShrink: 0,
        flexGrow: 0,
        width: "100%",
        backgroundColor: "#1a1a1a",
        display: "flex",
        alignItems: "center",
        borderBottom: "1px solid #333",
        overflow: "hidden",
        position: "relative"
      }}
      onMouseEnter={() => setIsPaused(true)}
      onMouseLeave={() => setIsPaused(false)}
    >
      {/* Left edge fade */}
      <div style={{
        position: "absolute",
        left: 0,
        top: 0,
        bottom: 0,
        width: "40px",
        background: "linear-gradient(to right, #1a1a1a, transparent)",
        zIndex: 2,
        pointerEvents: "none"
      }} />

      {/* Right edge fade */}
      <div style={{
        position: "absolute",
        right: 0,
        top: 0,
        bottom: 0,
        width: "40px",
        background: "linear-gradient(to left, #1a1a1a, transparent)",
        zIndex: 2,
        pointerEvents: "none"
      }} />

      <div style={{
        display: "inline-flex",
        animation: `marquee ${animationDuration}s linear infinite`,
        animationPlayState: isPaused ? "paused" : "running",
        whiteSpace: "nowrap"
      }}>
        {renderHeadlines("a")}
        {renderHeadlines("b") /* duplicate set so the scroll loops seamlessly */}
      </div>

      <style>
        {`
          @keyframes marquee {
            0%   { transform: translateX(0%); }
            100% { transform: translateX(-50%); }
          }
        `}
      </style>
    </div>
  );
}

function WorldMap() {
  const [viewport, setViewport] = useState({
    latitude: 20,
    longitude: 0,
    zoom: 1.5
  });

  const [hotspots, setHotspots] = useState([]);
  const [selectedSpot, setSelectedSpot] = useState(null);
  const [stocks, setStocks] = useState([
    { name: "OilCorp", value: -2.3 },
    { name: "SteelInc", value: 1.1 },
    { name: "TechGlobal", value: -0.8 },
    { name: "AgriWorld", value: 0.5 }
  ]);

  useEffect(() => {
    fetch("http://localhost:5000/api/news")
      .then(res => res.json())
      .then(data => {
        if (data.hotspots) {
          setHotspots(data.hotspots);
        } else {
          setHotspots([]);
        }
      })
      .catch(err => {
        console.error(err);
        setHotspots([]);
      });
  }, []);

  // Dummy animation: randomly adjust stock values every 3 seconds
  useEffect(() => {
    const interval = setInterval(() => {
      setStocks(prev =>
        prev.map(stock => {
          const change = (Math.random() - 0.5) * 0.5;
          return { ...stock, value: +(stock.value + change).toFixed(2) };
        })
      );
    }, 3000);
    return () => clearInterval(interval);
  }, []);

  const handleComingSoon = (feature) => {
    alert(`${feature} feature coming soon!`);
  };

  return (
    <div style={{ fontFamily: "Inter, Segoe UI, Roboto, sans-serif", height: "100vh", display: "flex", flexDirection: "column", backgroundColor: "#0d0d0d", color: "#fff" }}>

      {/* Top Navigation Bar */}
      <div style={{
        height: "60px",
        backgroundColor: "#111",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 20px",
        boxShadow: "0 2px 6px rgba(0,0,0,0.6)",
        flexShrink: 0
      }}>
        <h1 style={{ fontSize: "20px", margin: 0, color: "#fff" }}>🌐 Geopolitical Dashboard</h1>
        <div>
          <button onClick={() => handleComingSoon("Analytics")} style={navButtonStyle}>Analytics</button>
          <button onClick={() => handleComingSoon("Filters")} style={navButtonStyle}>Filters</button>
          <button onClick={() => handleComingSoon("Reports")} style={navButtonStyle}>Reports</button>
          <button onClick={() => handleComingSoon("Settings")} style={navButtonStyle}>Settings</button>
        </div>
      </div>

      {/* Breaking News Marquee at the top */}
      <BreakingNewsMarquee hotspots={hotspots} />

      {/* Map in the middle */}
      <div style={{ flex: 1, position: "relative" }}>
        <ReactMapGL
          {...viewport}
          width="100%"
          height="100%"
          mapStyle="mapbox://styles/mapbox/streets-v12"
          mapboxApiAccessToken={process.env.REACT_APP_MAPBOX_TOKEN}
          onViewportChange={setViewport}
        >
          {hotspots.map((spot, i) => (
            <Marker key={i} latitude={spot.lat} longitude={spot.lng}>
              <div
                onClick={() => setSelectedSpot(spot)}
                style={{
                  cursor: "pointer",
                  backgroundColor: "#e63946",
                  borderRadius: "50%",
                  width: "18px",
                  height: "18px",
                  border: "2px solid #fff",
                  boxShadow: "0 0 10px rgba(230,57,70,0.8)",
                  transition: "transform 0.2s ease"
                }}
                onMouseEnter={e => e.currentTarget.style.transform = "scale(1.3)"}
                onMouseLeave={e => e.currentTarget.style.transform = "scale(1)"}
              />
            </Marker>
          ))}

          {selectedSpot && (
            <Popup
              latitude={selectedSpot.lat}
              longitude={selectedSpot.lng}
              onClose={() => setSelectedSpot(null)}
              closeOnClick={false}
              anchor="top"
            >
              <div style={{
                maxWidth: "260px",
                padding: "12px",
                borderRadius: "8px",
                backgroundColor: "#111",
                color: "#fff",
                boxShadow: "0 4px 12px rgba(0,0,0,0.6)",
                animation: "fadeIn 0.3s ease"
              }}>
                <strong style={{ color: "#0077cc" }}>{selectedSpot.title}</strong>
                <br />
                <small style={{ color: "#aaa" }}>{selectedSpot.source}</small>
                <br />
                <a href={selectedSpot.url} target="_blank" rel="noopener noreferrer" style={{ color: "#e63946" }}>
                  Read more →
                </a>
              </div>
            </Popup>
          )}
        </ReactMapGL>
      </div>

      {/* Stock Prices Strip at bottom */}
      <div style={{
        height: "40px",
        backgroundColor: "#0d0d0d",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-around",
        color: "#fff",
        fontSize: "14px",
        borderTop: "1px solid #333",
        flexShrink: 0
      }}>
        {stocks.map((stock, i) => (
          <div key={i} style={{
            transition: "color 0.3s ease",
            cursor: "pointer"
          }}
          onMouseEnter={e => e.currentTarget.style.color = "#0077cc"}
          onMouseLeave={e => e.currentTarget.style.color = "#fff"}
          >
            {stock.name}{" "}
            <span style={{ color: stock.value >= 0 ? "#2ecc71" : "#e63946" }}>
              {stock.value >= 0 ? "▲" : "▼"} {stock.value}%
            </span>
          </div>
        ))}
      </div>
    </div>
  );
}

const navButtonStyle = {
  backgroundColor: "#222",
  color: "#fff",
  border: "none",
  padding: "8px 12px",
  marginLeft: "10px",
  borderRadius: "4px",
  cursor: "pointer",
  fontSize: "14px",
  transition: "background-color 0.2s ease"
};

export default WorldMap;
